text:
DNA（脱氧核糖核酸）双螺旋结构是生命遗传信息的载体。它由两条反向平行的糖磷酸骨架盘绕而成，中间通过四种不同的含氮碱基相互配对连接，形成类似旋转阶梯的形态。

在下方的 3D 模型中，你可以直观地观察到 A（腺嘌呤）总是与 T（胸腺嘧啶）配对，G（鸟嘌呤）总是与 C（胞嘧啶）配对。**你可以自由旋转、缩放模型，并点击任意碱基或骨架来深入了解它们的功能。**

```show-widget
{"title": "dna_double_helix_3d", "widget_code": "<style>
canvas { display: block; width: 100% !important; height: 420px !important; cursor: grab; }
canvas:active { cursor: grabbing; }
#controls { display: flex; align-items: center; justify-content: center; gap: 16px; padding: 12px 0 0; font-size: 13px; color: var(--color-text-secondary); flex-wrap: wrap; }
.legend-item { display: flex; align-items: center; gap: 6px; cursor: pointer; transition: opacity 0.2s; }
.legend-item:hover { opacity: 0.8; }
.dot { width: 10px; height: 10px; border-radius: 50%; display: inline-block; }
.hint { width: 100%; text-align: center; font-size: 12px; color: var(--color-text-tertiary); margin-top: 4px; }
</style>

<canvas id="c"></canvas>
<div id="controls">
  <span class="legend-item" onclick="window.__widgetSendMessage('详细介绍 DNA 中的腺嘌呤 (A)')">
    <span class="dot" style="background: #D85A30;"></span> 腺嘌呤 (A)
  </span>
  <span class="legend-item" onclick="window.__widgetSendMessage('详细介绍 DNA 中的胸腺嘧啶 (T)')">
    <span class="dot" style="background: #EF9F27;"></span> 胸腺嘧啶 (T)
  </span>
  <span class="legend-item" onclick="window.__widgetSendMessage('详细介绍 DNA 中的鸟嘌呤 (G)')">
    <span class="dot" style="background: #378ADD;"></span> 鸟嘌呤 (G)
  </span>
  <span class="legend-item" onclick="window.__widgetSendMessage('详细介绍 DNA 中的胞嘧啶 (C)')">
    <span class="dot" style="background: #639922;"></span> 胞嘧啶 (C)
  </span>
  <span class="legend-item" onclick="window.__widgetSendMessage('详细介绍 DNA 的磷酸二酯骨架')">
    <span class="dot" style="background: #7F77DD;"></span> 骨架
  </span>
  <div class="hint">提示：支持鼠标拖拽旋转、滚轮缩放。点击 3D 模型中的任意节点可获取详细说明。</div>
</div>

<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js" onload="init()"></script>
<script>
var scene, camera, renderer, controls;

function init() {
  if (!window.THREE || !THREE.OrbitControls) return;
  var canvas = document.getElementById('c');
  var W = canvas.clientWidth, H = 420;
  renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(devicePixelRatio, 2));

  scene = new THREE.Scene();
  camera = new THREE.PerspectiveCamera(35, W / H, 0.1, 1000);
  camera.position.set(0, 0, 24);

  scene.add(new THREE.AmbientLight(0xffffff, 0.65));
  var sun = new THREE.DirectionalLight(0xffffff, 0.85);
  sun.position.set(10, 15, 10);
  scene.add(sun);

  controls = new THREE.OrbitControls(camera, canvas);
  controls.enableDamping = true;
  controls.dampingFactor = 0.08;
  controls.autoRotate = true;
  controls.autoRotateSpeed = 1.5;
  controls.enablePan = false;

  function animate() {
    requestAnimationFrame(animate);
    controls.update();
    renderer.render(scene, camera);
  }
  animate();
}
if (window.THREE && THREE.OrbitControls) init();

// --- Scene Generation ---
setTimeout(() => {
  if (!scene) return;

  const dnaGroup = new THREE.Group();
  // Tilt the DNA slightly for a more dynamic viewing angle
  dnaGroup.rotation.z = Math.PI / 12;
  dnaGroup.rotation.x = Math.PI / 24;
  scene.add(dnaGroup);

  // Color palette matching the design guidelines (400 stops for standard materials)
  const mats = {
    A: new THREE.MeshLambertMaterial({ color: 0xD85A30 }), // Coral
    T: new THREE.MeshLambertMaterial({ color: 0xEF9F27 }), // Amber
    G: new THREE.MeshLambertMaterial({ color: 0x378ADD }), // Blue
    C: new THREE.MeshLambertMaterial({ color: 0x639922 }), // Green
    S1: new THREE.MeshLambertMaterial({ color: 0x7F77DD }), // Purple
    S2: new THREE.MeshLambertMaterial({ color: 0x1D9E75 })  // Teal
  };

  const numPairs = 32;
  const radius = 2.4;
  const heightStep = 0.55;
  const angleStep = Math.PI * 0.18; // ~32.4 degrees per step

  // Geometry
  const sphereGeo = new THREE.SphereGeometry(0.35, 16, 16);

  // Half cylinder setup so that its base sits at (0,0,0) and extends along +Z
  const halfCylGeo = new THREE.CylinderGeometry(0.12, 0.12, radius, 12);
  halfCylGeo.translate(0, radius / 2, 0);
  halfCylGeo.rotateX(Math.PI / 2);

  const points1 = [];
  const points2 = [];
  const clickTargets = [];

  // Sequence patterns (A-T, T-A, G-C, C-G)
  const pairs = [
    { l: 'A', r: 'T', ln: '腺嘌呤 (A)', rn: '胸腺嘧啶 (T)' },
    { l: 'G', r: 'C', ln: '鸟嘌呤 (G)', rn: '胞嘧啶 (C)' },
    { l: 'T', r: 'A', ln: '胸腺嘧啶 (T)', rn: '腺嘌呤 (A)' },
    { l: 'C', r: 'G', ln: '胞嘧啶 (C)', rn: '鸟嘌呤 (G)' }
  ];
  // Pseudo-random sequence to look organic
  const sequence = [0, 2, 1, 3, 0, 1, 2, 3, 1, 2, 0, 3, 1, 0, 2, 3, 2, 1, 0, 3, 1, 2, 0, 1, 3, 2, 0, 1, 2, 3, 0, 1];

  for (let i = 0; i < numPairs; i++) {
    const angle = i * angleStep;
    const y = (i - numPairs / 2 + 0.5) * heightStep;

    // Calculate positions for the two strands
    const p1 = new THREE.Vector3(Math.cos(angle) * radius, y, Math.sin(angle) * radius);
    const p2 = new THREE.Vector3(Math.cos(angle + Math.PI) * radius, y, Math.sin(angle + Math.PI) * radius);

    points1.push(p1);
    points2.push(p2);

    // Backbone nodes (Sugars/Phosphates)
    const n1 = new THREE.Mesh(sphereGeo, mats.S1);
    n1.position.copy(p1);
    n1.name = "磷酸二酯骨架";
    dnaGroup.add(n1);
    clickTargets.push(n1);

    const n2 = new THREE.Mesh(sphereGeo, mats.S2);
    n2.position.copy(p2);
    n2.name = "磷酸二酯骨架";
    dnaGroup.add(n2);
    clickTargets.push(n2);

    // Base pairs (Hydrogen bonds)
    const pairObj = pairs[sequence[i]];

    // Left half (from center to Strand 1)
    const b1 = new THREE.Mesh(halfCylGeo, mats[pairObj.l]);
    b1.position.set(0, y, 0);
    b1.lookAt(p1); // Orient the +Z axis towards p1
    b1.name = pairObj.ln;
    dnaGroup.add(b1);
    clickTargets.push(b1);

    // Right half (from center to Strand 2)
    const b2 = new THREE.Mesh(halfCylGeo, mats[pairObj.r]);
    b2.position.set(0, y, 0);
    b2.lookAt(p2);
    b2.name = pairObj.rn;
    dnaGroup.add(b2);
    clickTargets.push(b2);
  }

  // Continuous smooth backbones (Tubes)
  const curve1 = new THREE.CatmullRomCurve3(points1);
  const tubeGeo1 = new THREE.TubeGeometry(curve1, 100, 0.12, 8, false);
  const tube1 = new THREE.Mesh(tubeGeo1, mats.S1);
  tube1.name = "磷酸二酯骨架";
  dnaGroup.add(tube1);
  clickTargets.push(tube1);

  const curve2 = new THREE.CatmullRomCurve3(points2);
  const tubeGeo2 = new THREE.TubeGeometry(curve2, 100, 0.12, 8, false);
  const tube2 = new THREE.Mesh(tubeGeo2, mats.S2);
  tube2.name = "磷酸二酯骨架";
  dnaGroup.add(tube2);
  clickTargets.push(tube2);

  // Interaction: Raycasting for drill-down clicks
  const canvas = document.getElementById('c');
  let dragDist = 0, startX, startY;

  canvas.addEventListener('mousedown', function(e) {
    startX = e.clientX;
    startY = e.clientY;
    dragDist = 0;
  });

  canvas.addEventListener('mousemove', function(e) {
    dragDist += Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY);
  });

  canvas.addEventListener('click', function(e) {
    if (dragDist > 5) return; // Distinguish click from camera drag

    const rect = canvas.getBoundingClientRect();
    const mouse = new THREE.Vector2();
    mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;

    const raycaster = new THREE.Raycaster();
    raycaster.setFromCamera(mouse, camera);

    const hits = raycaster.intersectObjects(clickTargets);
    if (hits.length > 0) {
      const targetName = hits[0].object.name;
      window.__widgetSendMessage('详细介绍 DNA 中的' + targetName);
    }
  });
}, 100);
</script>"}
```

**关于该结构的几点核心事实：**
* **严格的碱基互补配对**：模型中心的连线代表了氢键。A 与 T 之间通过 2 个氢键连接，而 G 与 C 之间通过 3 个氢键连接，这种特异性保证了 DNA 复制时的精确性。
* **反向平行（Antiparallel）**：组成双螺旋的两条骨架在方向上是相反的（一条为 5' 到 3'，另一条为 3' 到 5'），这是 DNA 聚合酶能够正确读取和复制序列的前提。
* **信息存储**：DNA 骨架本身是统一且重复的，但中间四种碱基（A/T/C/G）的排列顺序（即序列）构成了生命体所有的遗传密码。
